import React, { useState, useEffect } from 'react';
import { Spinner, Button } from 'react-bootstrap';
import { Download, ZoomIn, ZoomOut } from 'lucide-react';
import { downloadDocument } from '../api';
import { toast } from 'react-toastify';
import './DocumentPreview.css';

const DocumentPreview = ({ document }) => {
  const [loading, setLoading] = useState(false);
  const [previewUrl, setPreviewUrl] = useState(null);
  const [zoom, setZoom] = useState(1);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (document?.id) {
      loadPreview();
    }
    
    return () => {
      if (previewUrl) {
        URL.revokeObjectURL(previewUrl);
      }
    };
  }, [document]);

  const loadPreview = async () => {
    setLoading(true);
    setError(null);
    
    try {
      // Extract document ID properly
      let docId = document.id;
      
      // Handle different ID formats
      if (typeof docId === 'string') {
        // Remove 'DOC' prefix if present
        docId = docId.replace(/^DOC0*/i, '');
        // Extract just the numeric part
        const numericMatch = docId.match(/\d+/);
        if (numericMatch) {
          docId = numericMatch[0];
        }
      }
      
      console.log('Loading document with ID:', docId, 'from original:', document.id);
      
      const response = await downloadDocument(docId);
      
      // Handle the response - could be blob or arraybuffer
      let blob;
      if (response.data instanceof Blob) {
        blob = response.data;
      } else {
        const contentType = response.headers?.['content-type'] || 'application/pdf';
        blob = new Blob([response.data], { type: contentType });
      }
      
      const url = URL.createObjectURL(blob);
      setPreviewUrl(url);
      
    } catch (error) {
      console.error('Error loading preview:', error);
      setError('Failed to load document preview');
      toast.error('Error loading document preview', {
        position: 'top-right',
        autoClose: 3000
      });
    } finally {
      setLoading(false);
    }
  };

  const handleDownload = async () => {
    try {
      // Extract document ID properly
      let docId = document.id;
      if (typeof docId === 'string') {
        docId = docId.replace(/^DOC0*/i, '');
        const numericMatch = docId.match(/\d+/);
        if (numericMatch) {
          docId = numericMatch[0];
        }
      }
      
      const response = await downloadDocument(docId);
      
      let blob;
      if (response.data instanceof Blob) {
        blob = response.data;
      } else {
        const contentType = response.headers?.['content-type'] || 'application/pdf';
        blob = new Blob([response.data], { type: contentType });
      }
      
      const url = URL.createObjectURL(blob);
      const link = window.document.createElement('a');
      link.href = url;
      link.download = document.fileName || `document_${document.id}`;
      window.document.body.appendChild(link);
      link.click();
      window.document.body.removeChild(link);
      URL.revokeObjectURL(url);
      
      toast.success('Document downloaded successfully', {
        position: 'top-right',
        autoClose: 3000
      });
    } catch (error) {
      console.error('Error downloading:', error);
      toast.error('Error downloading document', {
        position: 'top-right',
        autoClose: 3000
      });
    }
  };

  const isImage = (fileName) => {
    if (!fileName) return false;
    const ext = fileName.split('.').pop().toLowerCase();
    return ['jpg', 'jpeg', 'png', 'gif', 'webp'].includes(ext);
  };

  const isPDF = (fileName) => {
    if (!fileName) return false;
    const ext = fileName.split('.').pop().toLowerCase();
    return ext === 'pdf';
  };

  if (loading) {
    return (
      <div className="text-center py-5">
        <Spinner animation="border" variant="primary" />
        <p className="mt-3">Loading document...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="text-center py-5">
        <div className="alert alert-danger">{error}</div>
        <Button variant="primary" onClick={loadPreview}>
          Try Again
        </Button>
      </div>
    );
  }

  if (!previewUrl) {
    return (
      <div className="text-center py-5 text-muted">
        <p>No preview available</p>
      </div>
    );
  }

  return (
    <div className="preview-container">
      {/* Preview Controls */}
      <div className="preview-controls mb-3 d-flex align-items-center">
        <Button
          variant="outline-secondary"
          size="sm"
          onClick={() => setZoom(Math.max(0.5, zoom - 0.25))}
          disabled={zoom <= 0.5}
          title="Zoom Out"
        >
          <ZoomOut size={16} />
        </Button>
        <span className="mx-3 fw-bold">{(zoom * 100).toFixed(0)}%</span>
        <Button
          variant="outline-secondary"
          size="sm"
          onClick={() => setZoom(Math.min(2, zoom + 0.25))}
          disabled={zoom >= 2}
          title="Zoom In"
        >
          <ZoomIn size={16} />
        </Button>
        <Button
          variant="outline-secondary"
          size="sm"
          className="ms-2"
          onClick={() => setZoom(1)}
          title="Reset Zoom"
        >
          100%
        </Button>
        <Button
          variant="primary"
          size="sm"
          className="ms-auto"
          onClick={handleDownload}
        >
          <Download size={16} className="me-1" />
          Download
        </Button>
      </div>

      {/* Preview Content */}
      <div 
        className="preview-content" 
        style={{ 
          overflow: 'auto',
          maxHeight: '600px'
        }}
      >
        <div style={{ 
          transform: `scale(${zoom})`, 
          transformOrigin: 'top left',
          transition: 'transform 0.2s ease'
        }}>
          {isImage(document?.fileName) ? (
            <img
              src={previewUrl}
              alt="Document preview"
              className="preview-image"
              style={{ 
                maxWidth: '100%', 
                height: 'auto',
                display: 'block'
              }}
            />
          ) : isPDF(document?.fileName) ? (
            <iframe
              src={previewUrl}
              className="preview-iframe"
              title="PDF Preview"
              style={{ 
                width: '100%', 
                height: '600px', 
                border: 'none',
                display: 'block'
              }}
            />
          ) : (
            <div className="text-center py-5">
              <p>Preview not available for this file type.</p>
              <p className="text-muted small">File: {document?.fileName}</p>
              <Button variant="primary" onClick={handleDownload} className="mt-3">
                <Download size={16} className="me-1" />
                Download to View
              </Button>
            </div>
          )}
        </div>
      </div>

      {/* Document Info */}
      {document && (
        <div className="document-info mt-3 p-3 bg-light rounded">
          <div className="row">
            <div className="col-md-6">
              <small className="text-muted">Document ID:</small>
              <div>{document.id}</div>
            </div>
            <div className="col-md-6">
              <small className="text-muted">File Name:</small>
              <div>{document.fileName || 'N/A'}</div>
            </div>
            <div className="col-md-6 mt-2">
              <small className="text-muted">Employee:</small>
              <div>{document.employeeName || 'N/A'}</div>
            </div>
            <div className="col-md-6 mt-2">
              <small className="text-muted">Document Type:</small>
              <div>{document.documentType || 'N/A'}</div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default DocumentPreview;
